package abdmecdh

import (
	"encoding/base64"
	"testing"
)

// Test vectors from the Fidelius CLI README.
// These were generated by the Java/BouncyCastle implementation.
const (
	requesterPrivateKey = "Dnh316gsSfP+0kiNmEgsIekLsY6BQr7b++3rHQ8otAI="
	requesterPublicKey  = "BBbWU1fw1y1ErdKasIoQKKAWzq3N9ARcrukg7b1MpD3RHi9ofFAFhyIwMIA5p+iMCcLHkzQRoEFvCpNET1+tFtQ="
	requesterNonce      = "5mLKfBzxPw5+xVgxHu/iG+mzw+xIVN1dSFDrqB/KkIE="

	senderPrivateKey = "BJig2akHxYJKjA/uyUSzVris72DsOt95vVaG2ZzGSDE="
	senderPublicKey  = "BDWu6EFsroAUi8lnWZmLZCDZT7XbpsdEC7eeEtNnseHkDKa0igaRxDQOKro7KBaivUiTxdfvRK0mVlVgWGyZo98="
	senderNonce      = "IEEtSc15HpLboL/kjBhu+K2Hqro/aoTh9HAgXA5JwMM="

	plaintext = "Wormtail should never have been Potter cottage's secret keeper."
)

func TestGeneratorPointOnCurve(t *testing.T) {
	if !isOnCurve(curveGx, curveGy) {
		t.Fatal("generator point G is not on the curve")
	}
}

func TestPublicKeyOnCurve(t *testing.T) {
	pubBytes, err := base64.StdEncoding.DecodeString(requesterPublicKey)
	if err != nil {
		t.Fatal(err)
	}
	x, y, err := unmarshalUncompressed(pubBytes)
	if err != nil {
		t.Fatal(err)
	}
	if !isOnCurve(x, y) {
		t.Fatal("requester public key is not on the curve")
	}
}

func TestEncryptDecryptWithJavaKeys(t *testing.T) {
	encResp, err := Encrypt(EncryptionRequest{
		StringToEncrypt:    plaintext,
		SenderNonce:        senderNonce,
		RequesterNonce:     requesterNonce,
		SenderPrivateKey:   senderPrivateKey,
		RequesterPublicKey: requesterPublicKey,
	})
	if err != nil {
		t.Fatalf("encrypt failed: %v", err)
	}

	decResp, err := Decrypt(DecryptionRequest{
		EncryptedData:       encResp.EncryptedData,
		RequesterNonce:      requesterNonce,
		SenderNonce:         senderNonce,
		RequesterPrivateKey: requesterPrivateKey,
		SenderPublicKey:     senderPublicKey,
	})
	if err != nil {
		t.Fatalf("decrypt failed: %v", err)
	}

	if decResp.DecryptedData != plaintext {
		t.Fatalf("plaintext mismatch\ngot:  %s\nwant: %s", decResp.DecryptedData, plaintext)
	}
}

// TestCrossImplGoEncryptJavaDecrypt encrypts with Go-generated sender keys
// and Java-generated requester keys, then decrypts with the Java requester private key.
func TestCrossImplGoEncryptJavaDecrypt(t *testing.T) {
	goSender, err := GenerateKeyMaterial()
	if err != nil {
		t.Fatalf("generate go sender keys: %v", err)
	}

	original := ""

	encResp, err := Encrypt(EncryptionRequest{
		StringToEncrypt:    original,
		SenderNonce:        goSender.Nonce,
		RequesterNonce:     requesterNonce,
		SenderPrivateKey:   goSender.PrivateKey,
		RequesterPublicKey: requesterPublicKey,
	})
	if err != nil {
		t.Fatalf("encrypt failed: %v", err)
	}

	decResp, err := Decrypt(DecryptionRequest{
		EncryptedData:       encResp.EncryptedData,
		RequesterNonce:      requesterNonce,
		SenderNonce:         goSender.Nonce,
		RequesterPrivateKey: requesterPrivateKey,
		SenderPublicKey:     goSender.PublicKey,
	})
	if err != nil {
		t.Fatalf("decrypt failed: %v", err)
	}

	if decResp.DecryptedData != original {
		t.Fatalf("plaintext mismatch\ngot:  %s\nwant: %s", decResp.DecryptedData, original)
	}
}

