func TestRoundTrip(t *testing.T) {
	// Generate fresh keys for both parties
	requester, err := GenerateKeyMaterial()
	if err != nil {
		t.Fatalf("generate requester key material: %v", err)
	}
	sender, err := GenerateKeyMaterial()
	if err != nil {
		t.Fatalf("generate sender key material: %v", err)
	}

	original := "The secret is safe with Fidelius."

	// Encrypt
	encResp, err := Encrypt(EncryptionRequest{
		StringToEncrypt:    original,
		SenderNonce:        sender.Nonce,
		RequesterNonce:     requester.Nonce,
		SenderPrivateKey:   sender.PrivateKey,
		RequesterPublicKey: requester.PublicKey,
	})
	if err != nil {
		t.Fatalf("encrypt: %v", err)
	}

	// Decrypt
	decResp, err := Decrypt(DecryptionRequest{
		EncryptedData:       encResp.EncryptedData,
		RequesterNonce:      requester.Nonce,
		SenderNonce:         sender.Nonce,
		RequesterPrivateKey: requester.PrivateKey,
		SenderPublicKey:     sender.PublicKey,
	})
	if err != nil {
		t.Fatalf("decrypt: %v", err)
	}

	if decResp.DecryptedData != original {
		t.Fatalf("round trip failed\ngot:  %s\nwant: %s", decResp.DecryptedData, original)
	}
}

func BenchmarkGenerateKeyMaterial(b *testing.B) {
	for b.Loop() {
		_, err := GenerateKeyMaterial()
		if err != nil {
			b.Fatal(err)
		}
	}
}

func BenchmarkEncrypt(b *testing.B) {
	req := EncryptionRequest{
		StringToEncrypt:    plaintext,
		SenderNonce:        senderNonce,
		RequesterNonce:     requesterNonce,
		SenderPrivateKey:   senderPrivateKey,
		RequesterPublicKey: requesterPublicKey,
	}
	for b.Loop() {
		_, err := Encrypt(req)
		if err != nil {
			b.Fatal(err)
		}
	}
}

func BenchmarkDecrypt(b *testing.B) {
	encResp, err := Encrypt(EncryptionRequest{
		StringToEncrypt:    plaintext,
		SenderNonce:        senderNonce,
		RequesterNonce:     requesterNonce,
		SenderPrivateKey:   senderPrivateKey,
		RequesterPublicKey: requesterPublicKey,
	})
	if err != nil {
		b.Fatal(err)
	}
	req := DecryptionRequest{
		EncryptedData:       encResp.EncryptedData,
		RequesterNonce:      requesterNonce,
		SenderNonce:         senderNonce,
		RequesterPrivateKey: requesterPrivateKey,
		SenderPublicKey:     senderPublicKey,
	}
	b.ResetTimer()
	for b.Loop() {
		_, err := Decrypt(req)
		if err != nil {
			b.Fatal(err)
		}
	}
}

func BenchmarkRoundTrip(b *testing.B) {
	for b.Loop() {
		requester, err := GenerateKeyMaterial()
		if err != nil {
			b.Fatal(err)
		}
		sender, err := GenerateKeyMaterial()
		if err != nil {
			b.Fatal(err)
		}

		encResp, err := Encrypt(EncryptionRequest{
			StringToEncrypt:    plaintext,
			SenderNonce:        sender.Nonce,
			RequesterNonce:     requester.Nonce,
			SenderPrivateKey:   sender.PrivateKey,
			RequesterPublicKey: requester.PublicKey,
		})
		if err != nil {
			b.Fatal(err)
		}

		_, err = Decrypt(DecryptionRequest{
			EncryptedData:       encResp.EncryptedData,
			RequesterNonce:      requester.Nonce,
			SenderNonce:         sender.Nonce,
			RequesterPrivateKey: requester.PrivateKey,
			SenderPublicKey:     sender.PublicKey,
		})
		if err != nil {
			b.Fatal(err)
		}
	}
}
